                                    ))}
                                </div>
                            ) : (
                                <div className="text-slate-500 text-lg md:text-xl font-light italic">
                                    {isHost ? 'Click Auto Draw to begin!' : 'Waiting for host to start draw...'}
                                </div>
                            )}
                        </AnimatePresence>
                    </div>

                    {/* Player's Tickets Section */}
                    <div className="flex-1 flex flex-col items-center justify-start rounded-2xl relative w-full">
                        {myTickets && myTickets.length > 0 ? (
                            <div className="w-full flex flex-col gap-6">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-slate-400 font-bold tracking-widest uppercase">My Tickets ({myTickets.length}/3)</h3>
                                    {myTickets.length < 3 && safeGameState.status !== 'finished' && (
                                        <button
                                            onClick={buyTicket}
                                            disabled={user.walletBalance < 2}
                                            className="bg-action/20 text-action hover:bg-action hover:text-white transition-colors border border-action/30 px-3 py-1 rounded text-sm font-bold flex items-center gap-2"
                                        >
                                            <TicketIcon size={16} /> + Buy More (Γé╣2)
                                        </button>
                                    )}
                                </div>

                                <div className="flex flex-col xl:flex-row gap-4 w-full overflow-x-auto pb-4 custom-scrollbar">
                                    {myTickets.map((ticket, index) => (
                                        <div key={ticket.ticketId || index} className="min-w-full xl:min-w-[400px] flex-1">
                                            <Ticket
                                                ticketData={ticket}
                                                drawnNumbers={safeGameState.drawnNumbers}
                                                onClaim={handleClaimWin}
                                                winners={safeGameState.winners}
                                            />
                                        </div>
                                    ))}
                                </div>

                                {safeGameState.status === 'finished' && (
                                    <div className="w-full max-w-sm mx-auto text-center py-4 rounded-xl bg-slate-800 border-2 border-slate-600 text-slate-300 font-bold text-xl uppercase tracking-widest mt-4 flex flex-col items-center gap-4">
                                        <div>Game Finished</div>
                                        {isHost ? (
                                            <button
                                                onClick={() => socket.emit('restartGame', { roomCode, userId: user.id })}
                                                className="bg-highlight text-black hover:bg-neonGreen transition-colors px-6 py-2 rounded-lg text-sm flex items-center gap-2 normal-case tracking-normal"
                                            >
                                                <PlayCircle size={18} /> Play Next Game
                                            </button>
                                        ) : (
                                            <div className="text-sm text-slate-400 normal-case tracking-normal font-normal">Waiting for host to start next game...</div>
                                        )}
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="glass-panel p-12 text-center w-full max-w-lg border-dashed border-2 border-slate-700">
                                <TicketIcon size={64} className="mx-auto text-slate-500 mb-6" />
                                <h3 className="text-2xl font-bold mb-2">Ready to Play?</h3>
                                <p className="text-slate-400 mb-8">Buy a ticket to enter the current game round.</p>
                                <button
                                    onClick={buyTicket}
                                    disabled={user.walletBalance < 2 || safeGameState.status === 'finished'}
                                    className={`btn-neon text-xl py-4 px-12 inline-flex items-center gap-2 ${(user.walletBalance < 2 || safeGameState.status === 'finished') ? 'opacity-50 cursor-not-allowed' : ''}`}
                                >
                                    <TicketIcon /> {user.walletBalance < 2 ? 'Insufficient Balance' : 'Buy Ticket (Γé╣2)'}
                                </button>
                                {safeGameState.status === 'finished' && (
                                    <div className="mt-8 text-slate-400 flex justify-center">
                                        {isHost ? (
                                            <button
                                                onClick={() => socket.emit('restartGame', { roomCode, userId: user.id })}
                                                className="bg-highlight text-black hover:bg-neonGreen transition-colors px-6 py-2 rounded-lg text-sm flex items-center gap-2 font-bold"
                                            >
                                                <PlayCircle size={18} /> Play Next Game
                                            </button>
                                        ) : (
                                            "Waiting for host to start next game..."
                                        )}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                </div>

                {/* Right Col - Game Activity & Chat (Responsive Stack) */}
                <aside className="w-full xl:w-96 flex flex-col md:flex-row xl:flex-col gap-4 h-auto xl:h-[800px] xl:max-h-[calc(100vh-120px)] xl:sticky xl:top-[120px]">
                    {/* Players List */}
                    <div className="glass-panel p-4 md:p-6 flex flex-col flex-1 h-[250px] md:h-[400px] xl:h-1/2">
                        <h3 className="font-bold text-base md:text-lg mb-4 text-slate-300 border-b border-slate-800 pb-2 flex justify-between shrink-0">
                            Players <span>{safeGameState.players?.length}</span>
                        </h3>
                        <div className="flex-1 overflow-y-auto space-y-2 md:space-y-3 pr-2 custom-scrollbar">
                            {safeGameState.players?.map(p => (
                                <div key={p.id} className="flex justify-between items-center bg-slate-800/50 p-3 rounded-lg border border-slate-700/50">
                                    <span className={`${p.id === user.id ? 'text-action font-semibold' : 'text-slate-300'} flex items-center gap-2`}>
                                        {p.id === safeGameState.hostId && <Crown size={14} className="text-yellow-500" />}
                                        {p.name} {p.id === user.id && '(You)'}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Chat Panel */}
                    <div className="glass-panel p-4 flex flex-col h-[300px] md:h-[400px] xl:h-1/2 flex-1">
                        <h3 className="font-bold text-sm mb-2 text-slate-400 border-b border-slate-800 pb-2">Room Chat</h3>
                        <div className="flex-1 overflow-y-auto space-y-2 pr-2 custom-scrollbar mb-2 flex flex-col">
                            {messages.map(m => (
                                <div key={m.id} className={`text-sm p-2 rounded-lg max-w-[85%] break-words ${m.senderId === user.id ? 'bg-highlight/20 text-right self-end' : 'bg-slate-800/50 self-start'}`}>
                                    <div className="text-xs text-slate-500 font-bold mb-1">{m.senderName}</div>
                                    <div className="text-slate-200">{m.message}</div>
                                </div>
                            ))}
                            <div ref={chatEndRef} />
                        </div>
                        <form onSubmit={sendChat} className="flex gap-2 shrink-0">
                            <input
                                type="text"
                                value={chatInput}
                                onChange={e => setChatInput(e.target.value)}
                                placeholder="Type a message..."
                                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white outline-none focus:border-highlight"
                                maxLength={100}
                            />
                            <button type="submit" className="bg-highlight text-black px-3 py-2 rounded-lg text-sm font-bold disabled:opacity-50" disabled={!chatInput.trim()}>Send</button>
                        </form>
                    </div>
                </aside>

            </main>
        </div>
    );
}

import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { Sparkles, Play, Wallet, ShieldCheck, KeyRound, Crown, Trophy, Receipt, User } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Home() {
    const { user, setUser, socket, roomCode, gameType, setGameType } = useContext(AppContext);
    const [nameInput, setNameInput] = useState(user?.name || '');
    const [joinCode, setJoinCode] = useState('');
    const [selectedGame, setSelectedGame] = useState('houseee');
    const navigate = useNavigate();

    // Whenever we successfully receive a roomCode, navigate to the correct room type
    useEffect(() => {
        if (roomCode && gameType) {
            if (gameType === 'houseee') navigate('/room');
            if (gameType === 'tictactoe') navigate('/tictactoe');
            if (gameType === 'sos') navigate('/sos');
            if (gameType === 'snakesladders') navigate('/snakesladders');
            if (gameType === 'ludo') navigate('/ludo');
        }
    }, [roomCode, gameType, navigate]);

    const handleHostGame = () => {
        if (!nameInput.trim() && !user) return;

        let currentUser = user;
        if (!currentUser) {
            currentUser = {
                id: 'user_' + Math.random().toString(36).substr(2, 9),
                name: nameInput,
                walletBalance: 100,
                role: nameInput.toLowerCase() === 'admin' ? 'admin' : 'player'
            };
            setUser(currentUser);
        }

        socket.emit('createRoom', { userId: currentUser.id, userFallback: currentUser, gameType: selectedGame });
    };

    const handleJoinGame = (e) => {
        e.preventDefault();
        if (!nameInput.trim() && !user) return;

        let currentUser = user;
        if (!currentUser) {
            currentUser = {
                id: 'user_' + Math.random().toString(36).substr(2, 9),
                name: nameInput,
                walletBalance: 20,
                role: nameInput.toLowerCase() === 'admin' ? 'admin' : 'player'
            };
            setUser(currentUser);
        }

        if (joinCode.length === 5) {
            socket.emit('joinRoom', { userId: currentUser.id, roomCode: joinCode.toUpperCase(), userFallback: currentUser });
        } else {
            alert('Room code must be 5 characters');
        }
    };

    return (
        <div className="min-h-screen flex flex-col items-center justify-center p-4">
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="glass-panel p-8 md:p-12 w-full max-w-lg text-center relative overflow-hidden"
            >
                <div className="absolute top-0 right-0 p-4 opacity-10">
                    <Sparkles size={120} />
                </div>

                <h1 className="text-5xl md:text-6xl font-black mb-2 tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-neonGreen to-action drop-shadow-[0_0_15px_rgba(57,255,20,0.5)]">
                    HOUSEEE...
                </h1>
                <p className="text-slate-400 text-lg mb-8 font-light">Private Games for Real Friends.</p>

                {(!user) && (
                    <div className="text-left mb-6">
                        <label className="block text-slate-400 text-sm mb-2 ml-1">Choose your identity</label>
                        <input
                            type="text"
                            value={nameInput}
                            onChange={(e) => setNameInput(e.target.value)}
                            placeholder="Enter your name..."
                            className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white placeholder-slate-500 focus:outline-none focus:border-action focus:ring-1 focus:ring-action transition-all"
                            required
                        />
                    </div>
                )}

                {user && (
                    <div className="bg-slate-800/80 rounded-xl p-4 border border-slate-700 mb-6 relative overflow-hidden group hover:border-slate-600 transition-colors">
                        <div className="flex justify-between items-center mb-2 relative z-10">
                            <span className="text-slate-400">Welcome back,</span>
                            <span className="font-bold text-white text-xl">{user.name}</span>
                        </div>
                        <div className="flex justify-between items-center bg-slate-900 rounded-lg p-3 relative z-10">
                            <div className="flex items-center gap-2 text-action">
                                <Wallet size={20} />
                                <span>Wallet Balance</span>
                            </div>
                            <span className="text-2xl font-bold text-neonGreen">Γé╣{user.walletBalance}</span>
                        </div>
                        <div className="flex gap-2 mt-4 relative z-10 w-full">
                            <button onClick={() => navigate('/profile')} className="flex-1 bg-action/10 hover:bg-action/20 text-action border border-action/20 py-2 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 transition-colors">
                                <User size={16} /> Profile
                            </button>
                            <button onClick={() => navigate('/ledger')} className="flex-1 bg-slate-700/50 hover:bg-slate-700 text-slate-300 py-2 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 transition-colors">
                                <Receipt size={16} /> Ledger
                            </button>
                            <button onClick={() => navigate('/leaderboard')} className="flex-1 bg-yellow-500/10 hover:bg-yellow-500/20 text-yellow-500 border border-yellow-500/20 py-2 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 transition-colors">
                                <Trophy size={16} /> Leaders
                            </button>
                        </div>
                    </div>
                )}

                {/* GAME SELECTION */}
                <div className="mb-6 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-2">
                    <button
                        onClick={() => setSelectedGame('houseee')}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${selectedGame === 'houseee' ? 'bg-highlight/20 border-highlight text-highlight shadow-[0_0_15px_rgba(57,255,20,0.3)]' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                    >
                        <Sparkles size={24} className="mb-1" />
                        <span className="text-[10px] font-bold uppercase tracking-wider">Houseee</span>
                    </button>
                    <button
                        onClick={() => setSelectedGame('tictactoe')}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${selectedGame === 'tictactoe' ? 'bg-blue-500/20 border-blue-500 text-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.3)]' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                    >
                        <div className="text-xl font-black mb-1 leading-none tracking-widest px-1">X O</div>
                        <span className="text-[10px] font-bold uppercase tracking-wider text-center">Tic Tac Toe</span>
                    </button>
                    <button
                        onClick={() => setSelectedGame('sos')}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${selectedGame === 'sos' ? 'bg-red-500/20 border-red-500 text-red-500 shadow-[0_0_15px_rgba(239,68,68,0.3)]' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                    >
                        <div className="text-xl font-black mb-1 leading-none tracking-widest px-1">SOS</div>
                        <span className="text-[10px] font-bold uppercase tracking-wider text-center">S O S</span>
                    </button>
                    <button
                        onClick={() => setSelectedGame('snakesladders')}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all ${selectedGame === 'snakesladders' ? 'bg-green-500/20 border-green-500 text-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                    >
                        <div className="text-xl font-black mb-1 leading-none tracking-widest px-1">ΓÜä</div>
                        <span className="text-[10px] font-bold uppercase tracking-wider text-center">Snakes&Lad</span>
                    </button>
                    <button
                        onClick={() => setSelectedGame('ludo')}
                        className={`flex flex-col items-center justify-center p-3 rounded-xl border-2 transition-all col-span-2 md:col-span-1 lg:col-span-1 ${selectedGame === 'ludo' ? 'bg-purple-500/20 border-purple-500 text-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.3)]' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                    >
                        <div className="text-xl font-black mb-1 leading-none tracking-widest px-1">Γ£Ü</div>
                        <span className="text-[10px] font-bold uppercase tracking-wider text-center">Ludo</span>
                    </button>
                </div>

                <div className="space-y-4">
                    <button
                        onClick={handleHostGame}
                        disabled={!user && !nameInput.trim()}
                        className={`btn-neon w-full flex items-center justify-center gap-2 text-lg py-4 ${(!user && !nameInput) ? 'opacity-50' : ''}`}
                        style={{
                            backgroundColor: selectedGame === 'tictactoe' ? 'rgba(59, 130, 246, 0.2)' : selectedGame === 'sos' ? 'rgba(239, 68, 68, 0.2)' : selectedGame === 'snakesladders' ? 'rgba(34, 197, 94, 0.2)' : selectedGame === 'ludo' ? 'rgba(168, 85, 247, 0.2)' : undefined,
                            borderColor: selectedGame === 'tictactoe' ? '#3B82F6' : selectedGame === 'sos' ? '#EF4444' : selectedGame === 'snakesladders' ? '#22C55E' : selectedGame === 'ludo' ? '#A855F7' : undefined,
                            color: selectedGame === 'tictactoe' ? '#3B82F6' : selectedGame === 'sos' ? '#EF4444' : selectedGame === 'snakesladders' ? '#22C55E' : selectedGame === 'ludo' ? '#A855F7' : undefined,
                        }}
                    >
                        <Crown fill="currentColor" /> Host {selectedGame.toUpperCase()} Game
                    </button>

                    <div className="flex items-center gap-4 text-slate-500 text-sm my-4">
                        <div className="flex-1 h-px bg-slate-800"></div>
                        <span>OR JOIN EXISTING</span>
                        <div className="flex-1 h-px bg-slate-800"></div>
                    </div>

                    <form onSubmit={handleJoinGame} className="flex gap-2">
                        <input
                            type="text"
                            placeholder="5-Digit Code"
                            maxLength={5}
                            value={joinCode}
                            onChange={(e) => setJoinCode(e.target.value)}
                            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-center tracking-[0.5em] font-mono text-xl text-white uppercase focus:border-highlight focus:outline-none"
                            required
                        />
                        <button
                            type="submit"
                            disabled={!user && !nameInput.trim()}
                            className="bg-highlight text-black font-bold px-6 rounded-xl hover:bg-neonGreen transition-colors whitespace-nowrap"
                        >
                            <KeyRound size={24} />
                        </button>
                    </form>

                    {user?.role === 'admin' && (
                        <button
                            onClick={() => navigate('/admin')}
                            className="w-full text-slate-400 hover:text-white transition-colors flex items-center justify-center gap-2 mt-4"
                        >
                            <ShieldCheck size={18} /> Master Admin Panel
                        </button>
                    )}
                </div>
            </motion.div>
        </div>
    );
}

import React, { useEffect, useState, useContext } from 'react';
import { AppContext } from '../App';
import { useNavigate } from 'react-router-dom';
import { Trophy, ChevronLeft, CalendarClock } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Leaderboard() {
    const [leaders, setLeaders] = useState([]);
    const { user } = useContext(AppContext);
    const navigate = useNavigate();

    useEffect(() => {
        fetch(`${import.meta.env.VITE_BACKEND_URL || 'http://localhost:5000'}/api/leaderboard`)
            .then(res => res.json())
            .then(data => setLeaders(data))
            .catch(console.error);
    }, []);

    if (!user) {
        navigate('/');
        return null;
    }

    return (
        <div className="min-h-screen py-10 px-4 md:px-8 max-w-4xl mx-auto flex flex-col gap-8">
            <header className="flex items-center gap-4 glass-panel p-4 px-6 z-10">
                <button onClick={() => navigate('/')} className="text-slate-400 hover:text-white transition-colors">
                    <ChevronLeft size={28} />
                </button>
                <h1 className="text-2xl font-black uppercase tracking-widest text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-amber-600 flex items-center gap-3">
                    <Trophy className="text-yellow-500" /> Global Leaderboard
                </h1>
            </header>

            <main className="glass-panel p-6 md:p-10 flex-1">
                <div className="flex flex-col gap-4">
                    {leaders.length === 0 ? (
                        <div className="text-center text-slate-500 italic py-10">No data available yet...</div>
                    ) : (
                        leaders.map((leader, index) => (
                            <motion.div
                                key={leader.id}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: index * 0.1 }}
                                className={`flex items-center justify-between p-4 rounded-xl border ${index === 0 ? 'bg-yellow-500/10 border-yellow-500/30' :
                                        index === 1 ? 'bg-slate-300/10 border-slate-300/30' :
                                            index === 2 ? 'bg-amber-700/10 border-amber-700/30' :
                                                'bg-slate-800/50 border-slate-700/50'
                                    }`}
                            >
                                <div className="flex items-center gap-4">
                                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-lg ${index === 0 ? 'bg-yellow-500 text-black shadow-[0_0_15px_rgba(234,179,8,0.5)]' :
                                            index === 1 ? 'bg-slate-300 text-black' :
                                                index === 2 ? 'bg-amber-700 text-white' :
                                                    'bg-slate-800 text-slate-400'
                                        }`}>
                                        {index + 1}
                                    </div>
                                    <div>
                                        <div className={`font-bold text-lg ${leader.id === user.id ? 'text-action' : 'text-slate-200'}`}>
                                            {leader.name} {leader.id === user.id && '(You)'}
                                        </div>
                                    </div>
                                </div>
                                <div className="text-xl font-mono text-neonGreen font-bold">
                                    Γé╣{leader.walletBalance}
                                </div>
                            </motion.div>
                        ))
                    )}
                </div>
            </main>
        </div>
    );
}

import React, { useEffect, useState, useContext } from 'react';
import { AppContext } from '../App';
import { useNavigate } from 'react-router-dom';
import { ChevronLeft, Receipt, ArrowUpRight, ArrowDownRight } from 'lucide-react';
import { motion } from 'framer-motion';

export default function Ledger() {
    const [transactions, setTransactions] = useState([]);
    const { user } = useContext(AppContext);
    const navigate = useNavigate();

    useEffect(() => {
        if (!user?.id) return;
        fetch(`${import.meta.env.VITE_BACKEND_URL || 'http://localhost:5000'}/api/ledger/${user.id}`)
            .then(res => res.json())
            .then(data => setTransactions(data))
            .catch(console.error);
    }, [user?.id]);

    if (!user) {
        navigate('/');
        return null;
    }

    return (
        <div className="min-h-screen py-10 px-4 md:px-8 max-w-4xl mx-auto flex flex-col gap-8">
            <header className="flex items-center gap-4 glass-panel p-4 px-6 z-10">
                <button onClick={() => navigate('/')} className="text-slate-400 hover:text-white transition-colors">
                    <ChevronLeft size={28} />
                </button>
                <h1 className="text-2xl font-black uppercase tracking-widest text-slate-200 flex items-center gap-3">
                    <Receipt className="text-action" /> Transaction History
                </h1>
            </header>

            <main className="glass-panel p-6 md:p-10 flex-1">
                <div className="flex flex-col gap-3">
                    {transactions.length === 0 ? (
                        <div className="text-center text-slate-500 italic py-10">No transactions recorded yet...</div>
                    ) : (
                        transactions.map((tx, index) => {
                            const isCredit = tx.type === 'credit';
                            return (
                                <motion.div
                                    key={tx.id}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    className="flex items-center justify-between p-4 rounded-xl border bg-slate-800/50 border-slate-700/50 hover:bg-slate-800 transition-colors"
                                >
                                    <div className="flex items-center gap-4">
                                        <div className={`p-3 rounded-full ${isCredit ? 'bg-green-500/20 text-green-500' : 'bg-red-500/20 text-red-500'}`}>
                                            {isCredit ? <ArrowUpRight size={20} /> : <ArrowDownRight size={20} />}
                                        </div>
                                        <div>
                                            <div className="font-bold text-slate-200">{tx.description}</div>
                                            <div className="text-xs text-slate-500 mt-1">
                                                {new Date(tx.date).toLocaleString()}
                                            </div>
                                        </div>
                                    </div>
                                    <div className={`text-lg font-mono font-bold ${isCredit ? 'text-neonGreen' : 'text-red-400'}`}>
                                        {isCredit ? '+' : '-'}Γé╣{tx.amount}
                                    </div>
                                </motion.div>
                            );
                        })
                    )}
                </div>
            </main>
        </div>
    );
}

import React, { useContext, useState, useEffect } from 'react';
import { AppContext } from '../App';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Dice5, Trophy } from 'lucide-react';
import VoiceChat from '../components/VoiceChat';
import EmojiOverlay from '../components/EmojiOverlay';
import VFXOverlay from '../components/VFXOverlay';

// Ludo 52-step peripheral track coordinates (x=col, y=row)
// Mapped globally per typical Ludo layout.
const TRACK = [
    { x: 1, y: 6 }, { x: 2, y: 6 }, { x: 3, y: 6 }, { x: 4, y: 6 }, { x: 5, y: 6 },
    { x: 6, y: 5 }, { x: 6, y: 4 }, { x: 6, y: 3 }, { x: 6, y: 2 }, { x: 6, y: 1 }, { x: 6, y: 0 },
    { x: 7, y: 0 }, { x: 8, y: 0 },
    { x: 8, y: 1 }, { x: 8, y: 2 }, { x: 8, y: 3 }, { x: 8, y: 4 }, { x: 8, y: 5 },
    { x: 9, y: 6 }, { x: 10, y: 6 }, { x: 11, y: 6 }, { x: 12, y: 6 }, { x: 13, y: 6 }, { x: 14, y: 6 },
    { x: 14, y: 7 }, { x: 14, y: 8 },
    { x: 13, y: 8 }, { x: 12, y: 8 }, { x: 11, y: 8 }, { x: 10, y: 8 }, { x: 9, y: 8 },
    { x: 8, y: 9 }, { x: 8, y: 10 }, { x: 8, y: 11 }, { x: 8, y: 12 }, { x: 8, y: 13 }, { x: 8, y: 14 },
    { x: 7, y: 14 }, { x: 6, y: 14 },
    { x: 6, y: 13 }, { x: 6, y: 12 }, { x: 6, y: 11 }, { x: 6, y: 10 }, { x: 6, y: 9 },
    { x: 5, y: 8 }, { x: 4, y: 8 }, { x: 3, y: 8 }, { x: 2, y: 8 }, { x: 1, y: 8 }, { x: 0, y: 8 },
    { x: 0, y: 7 }, { x: 0, y: 6 }
];

const getGlobalPos = (color, relPos) => {
    if (relPos < 0 || relPos > 50) return null;
    const offsets = { red: 0, green: 13, yellow: 26, blue: 39 };
    return (offsets[color] + relPos) % 52;
};

const getPosCoordinates = (color, tokenIdx, relPos) => {
    if (relPos === -1) {
        // Precise clusters within the 4 round sandpits.
        // Pits are at x=1,y=1 (4x4), x=10,y=1, x=1,y=10, x=10,y=10
        // Centers are 2.5 and 11.5. Token radius offsets by ~0.7 cells.
        const bases = {
            blue: [{ x: 1.5, y: 1.5 }, { x: 3.5, y: 1.5 }, { x: 1.5, y: 3.5 }, { x: 3.5, y: 3.5 }],
            red: [{ x: 10.5, y: 1.5 }, { x: 12.5, y: 1.5 }, { x: 10.5, y: 3.5 }, { x: 12.5, y: 3.5 }],
            yellow: [{ x: 1.5, y: 10.5 }, { x: 3.5, y: 10.5 }, { x: 1.5, y: 12.5 }, { x: 3.5, y: 12.5 }],
            green: [{ x: 10.5, y: 10.5 }, { x: 12.5, y: 10.5 }, { x: 10.5, y: 12.5 }, { x: 12.5, y: 12.5 }]
        };
        return bases[color][tokenIdx];
    }

    if (relPos >= 0 && relPos <= 50) {
        return TRACK[getGlobalPos(color, relPos)];
    }

    // Home Stretch (51 - 55)
    // Yellow home row is y=7, filling x=1 to 5
    // Blue home col is x=7, filling y=1 to 5
    // Red home row is y=7, filling x=13 to 9
    // Green home col is x=7, filling y=13 to 9
    const steps = relPos - 50;
    if (color === 'yellow') return { x: steps, y: 7 };
    if (color === 'blue') return { x: 7, y: steps };
    if (color === 'red') return { x: 14 - steps, y: 7 };
    if (color === 'green') return { x: 7, y: 14 - steps };

    // 56 (Finished in center)
    return { x: 7, y: 7 };
};

const COLOR_MAP = {
    red: '#EF4444',
    green: '#22C55E',
    yellow: '#EAB308',
    blue: '#3B82F6'
};

export default function Ludo() {
    const { user, socket, roomCode, gameState, setRoomCode, setGameType } = useContext(AppContext);
    const navigate = useNavigate();

    const [isRolling, setIsRolling] = useState(false);
    const [currentFace, setCurrentFace] = useState(1);

    const safeGameState = gameState || { players: [], winner: null, turn: null, tokens: {}, colors: {}, history: [] };
    const isMyTurn = safeGameState.turn === user.id;

    // Keep dice dots in sync, and flicker randomly while rolling
    useEffect(() => {
        let interval;
        if (isRolling) {
            interval = setInterval(() => {
                setCurrentFace(Math.floor(Math.random() * 6) + 1);
            }, 80); // Fast 80ms flicker
        } else if (safeGameState.lastDice) {
            setCurrentFace(safeGameState.lastDice);
        }
        return () => clearInterval(interval);
    }, [isRolling, safeGameState.lastDice]);

    const [vfxType, setVfxType] = useState(null);
    const [vfxTrigger, setVfxTrigger] = useState(0);

    const prevHistoryLength = React.useRef(safeGameState.history?.length || 0);
    useEffect(() => {
        if (safeGameState.history?.length > prevHistoryLength.current) {
            const latest = safeGameState.history[safeGameState.history.length - 1];
            if (latest.type === 'capture') {
                setVfxType('kill');
                setVfxTrigger(v => v + 1);
            }
        }
        prevHistoryLength.current = safeGameState.history?.length || 0;
    }, [safeGameState.history]);

    const prevWinner = React.useRef(safeGameState.winner);
    useEffect(() => {
        if (!prevWinner.current && safeGameState.winner) {
            setVfxType('victory');
            setVfxTrigger(v => v + 1);
        }
        prevWinner.current = safeGameState.winner;
    }, [safeGameState.winner]);

    const handleRoll = () => {
        if (!isMyTurn || safeGameState.winner || safeGameState.diceRolled) return;
        setIsRolling(true);
        socket.emit('rollDiceLudo', { roomCode, userId: user.id });
        setTimeout(() => {
            setIsRolling(false);
        }, 600);
    };

    const handleTokenClick = (tokenIndex, ownerId) => {
        if (!isMyTurn || ownerId !== user.id || !safeGameState.diceRolled) return;

        const dice = safeGameState.lastDice;
        const pos = safeGameState.tokens[user.id][tokenIndex];

        // Validation check for UI feedback
        let valid = false;
        if (pos === -1 && dice === 6) valid = true;
        if (pos >= 0 && pos + dice <= 56) valid = true;

        if (valid) {
            socket.emit('moveTokenLudo', { roomCode, userId: user.id, tokenIndex });
        }
    };

    const leaveRoom = () => {
        setRoomCode(null);
        setGameType(null);
        navigate('/');
    };

    const renderBoardBackground = () => {
        const cells = [];

        // 1. Render giant sand-pits
        const sandPits = [
            { x: 1, y: 1, color: 'blue' },
            { x: 10, y: 1, color: 'red' },
            { x: 1, y: 10, color: 'yellow' },
            { x: 10, y: 10, color: 'green' }
        ];

        sandPits.forEach(pit => {
            cells.push(
                <div key={`pit-${pit.color}`} className="absolute bg-[#e8dcb8] rounded-full shadow-[0_10px_20px_rgba(0,0,0,0.6),inset_0_0_30px_rgba(0,0,0,0.2)] border-[3px] md:border-4 border-[#c7b58c] z-0"
                    style={{
                        left: `${(pit.x / 15) * 100}%`,
                        top: `${(pit.y / 15) * 100}%`,
                        width: `${(4 / 15) * 100}%`,
                        height: `${(4 / 15) * 100}%`,
                        backgroundImage: `url("https://www.transparenttextures.com/patterns/sandpaper.png")`
                    }}
                >
                    {/* Token indentations */}
                    {[{ tx: 0.5, ty: 0.5 }, { tx: 2.5, ty: 0.5 }, { tx: 0.5, ty: 2.5 }, { tx: 2.5, ty: 2.5 }].map((pos, i) => (
                        <div key={`ind-${i}`} className="absolute bg-[#d6c79e] rounded-full shadow-[inset_0_5px_10px_rgba(0,0,0,0.5)] border border-[#a89874]" style={{
                            left: `${(pos.tx / 4) * 100}%`,
                            top: `${(pos.ty / 4) * 100}%`,
                            width: `${1 / 4 * 100}%`,
                            height: `${1 / 4 * 100}%`,
                        }} />
                    ))}
                </div>
            );
        });

        // 2. Render Path tiles
        for (let r = 0; r < 15; r++) {
            for (let c = 0; c < 15; c++) {
                const isPath = TRACK.some(pos => pos.x === c && pos.y === r);
                const isHomeStretch =
                    (r === 7 && c >= 1 && c <= 5) || // Yellow
                    (c === 7 && r >= 1 && r <= 5) || // Blue
                    (r === 7 && c >= 9 && c <= 13) || // Red
                    (c === 7 && r >= 9 && r <= 13);   // Green

                if (isPath || isHomeStretch) {
                    let bg = 'bg-[#f0c386]'; // default light wood
                    let isSafe = false;

                    // Starts (match exact screenshot colors)
                    if (r === 6 && c === 1) bg = 'bg-[#FDE047]'; // Yellow
                    else if (r === 1 && c === 8) bg = 'bg-[#93C5FD]'; // Blue
                    else if (r === 8 && c === 13) bg = 'bg-[#FCA5A5]'; // Red
                    else if (r === 13 && c === 6) bg = 'bg-[#86EFAC]'; // Green

                    // Other Safes
                    else if (r === 2 && c === 6) { bg = 'bg-[#93C5FD]'; isSafe = true; } // Blue arm safe
                    else if (r === 6 && c === 12) { bg = 'bg-[#FCA5A5]'; isSafe = true; } // Red arm safe
                    else if (r === 12 && c === 8) { bg = 'bg-[#86EFAC]'; isSafe = true; } // Green arm safe
                    else if (r === 8 && c === 2) { bg = 'bg-[#FDE047]'; isSafe = true; } // Yellow arm safe

                    // Home stretches
                    else if (r === 7 && c >= 1 && c <= 5) bg = 'bg-[#FDE047]';
                    else if (c === 7 && r >= 1 && r <= 5) bg = 'bg-[#93C5FD]';
                    else if (r === 7 && c >= 9 && c <= 13) bg = 'bg-[#FCA5A5]';
                    else if (c === 7 && r >= 9 && r <= 13) bg = 'bg-[#86EFAC]';

                    cells.push(
                        <div key={`${r}-${c}`}
                            className={`absolute border-[1px] md:border-[2px] border-[#825424] shadow-[inset_0_0_5px_rgba(0,0,0,0.3)] ${bg} flex items-center justify-center z-10 rounded-[1px]`}
                            style={{
                                left: `${(c / 15) * 100}%`,
                                top: `${(r / 15) * 100}%`,
                                width: `${100 / 15}%`,
                                height: `${100 / 15}%`,
                                backgroundImage: `url("https://www.transparenttextures.com/patterns/wood-pattern.png")`
                            }}
                        >
                            {isSafe && <span className="text-white/60 text-xs md:text-xl drop-shadow-md pb-1 pointer-events-none opacity-50 block">≡ƒì╖</span>}
                        </div>
                    );
                }
            }
        }

        // 3. Center Cross Triangles
        cells.push(
            <div key="center-home" className="absolute z-10" style={{
                left: `${(6 / 15) * 100}%`, top: `${(6 / 15) * 100}%`, width: `${(3 / 15) * 100}%`, height: `${(3 / 15) * 100}%`
            }}>
                <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-[0_0_15px_rgba(0,0,0,0.6)]">
                    <polygon points="0,0 50,50 0,100" fill="#FACC15" stroke="#78350F" strokeWidth="2" />
                    <polygon points="0,0 100,0 50,50" fill="#60A5FA" stroke="#78350F" strokeWidth="2" />
                    <polygon points="100,0 100,100 50,50" fill="#F87171" stroke="#78350F" strokeWidth="2" />
                    <polygon points="0,100 100,100 50,50" fill="#4ADE80" stroke="#78350F" strokeWidth="2" />
                </svg>
            </div>
        );

        return cells;
    };

    const renderPlayerTags = () => {
        return safeGameState.players?.map(p => {
            const pColorName = safeGameState.colors?.[p.id];
            if (!pColorName) return null;

            // Positioning exactly over the 4 quadrants corresponding to the reference image
            let posProps = {};
            if (pColorName === 'blue') posProps = { left: '8%', top: '2%' };
            if (pColorName === 'red') posProps = { right: '8%', top: '2%' };
            if (pColorName === 'yellow') posProps = { left: '8%', bottom: '2%' };
            if (pColorName === 'green') posProps = { right: '25%', bottom: '2%' }; // Kept away from Dice!

            const isTurn = safeGameState.turn === p.id;

            return (
                <div key={p.id} className={`absolute flex flex-col items-center gap-1 z-30 pointer-events-none transition-all duration-300 ${isTurn ? 'scale-110 drop-shadow-[0_0_20px_#FDE047]' : 'opacity-90'}`} style={posProps}>
                    <div className="w-10 h-10 md:w-16 md:h-16 rounded-xl border-4 flex items-center justify-center font-black text-white text-xl md:text-3xl shadow-[0_5px_15px_rgba(0,0,0,0.8)]" style={{
                        backgroundColor: COLOR_MAP[pColorName],
                        borderColor: '#5c3a21',
                        backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")'
                    }}>
                        ≡ƒæñ
                    </div>
                    <div className={`
                        bg-[#825424] border-2 border-[#4a2e15] rounded text-white text-[8px] md:text-xs font-bold shadow-lg px-2 md:px-4 py-0.5 md:py-1 truncate max-w-[80px] md:max-w-[120px] text-center
                    `} style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")' }}>
                        {p.name}
                        {p.id === user.id && <span className="text-yellow-300 text-[6px] md:text-[8px] block">(YOU)</span>}
                    </div>
                </div>
            )
        });
    };

    if (!user || !roomCode) return null;

    return (
        <div className="min-h-screen flex flex-col items-center p-2 md:p-4 text-emerald-900" style={{ backgroundColor: '#2d3a1f' }}>
            <EmojiOverlay />
            <VFXOverlay type={vfxType} trigger={vfxTrigger} message={safeGameState.winner === user.id ? 'VICTORY' : 'DEFEAT'} />

            {/* Custom Wooden Header Bar */}
            <motion.div initial={{ y: -20, opacity: 0 }} animate={{ y: 0, opacity: 1 }} className="w-full max-w-6xl flex flex-wrap items-center justify-between mb-4 bg-[#633a1e] p-3 md:p-4 rounded-2xl border-[3px] md:border-[4px] border-[#3d2210] shadow-[0_15px_30px_rgba(0,0,0,0.6)] gap-3" style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")' }}>
                <div className="flex items-center gap-3 md:gap-4">
                    <button onClick={leaveRoom} className="p-3 bg-red-600/90 text-white hover:bg-red-500 rounded-xl transition-colors shadow-lg border-2 border-red-900">
                        <LogOut size={20} />
                    </button>
                    <div>
                        <div className="text-[10px] md:text-xs text-amber-300 font-black tracking-widest uppercase drop-shadow-md">Classic Board</div>
                        <div className="text-lg md:text-xl font-black text-white tracking-[0.2em]">{roomCode}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-[#4a2e15] p-2 rounded-xl border border-[#2b190a] shadow-inner">
                    <VoiceChat />
                </div>
            </motion.div>

            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="w-full max-w-6xl flex justify-center pb-20 relative">

                {/* FULL SCREEN HERO BOARD */}
                <div className="w-full aspect-square max-w-[95vw] md:max-w-[85vh] xl:max-w-[900px] xl:h-[900px] mx-auto rounded-md md:rounded-[1rem] border-[10px] md:border-[16px] border-[#5c3a21] p-[1%] relative z-10 shadow-[0_20px_50px_rgba(0,0,0,0.9)] overflow-hidden" style={{ backgroundColor: '#5c8a32', backgroundImage: 'url("https://www.transparenttextures.com/patterns/dark-matter.png")' }}>

                    <div className="w-full h-full relative" style={{ display: 'grid', gridTemplateColumns: 'repeat(15, 1fr)', gridTemplateRows: 'repeat(15, 1fr)' }}>
                        {renderBoardBackground()}
                        {renderPlayerTags()}

                        {/* Token Overlay Rendering */}
                        <AnimatePresence>
                            {safeGameState.players?.map(p => {
                                const pColorName = safeGameState.colors?.[p.id];
                                const tokensArray = safeGameState.tokens?.[p.id];
                                if (!pColorName || !tokensArray) return null;

                                return tokensArray.map((relPos, tIdx) => {
                                    const coords = getPosCoordinates(pColorName, tIdx, relPos);
                                    if (!coords) return null;

                                    const canMove = isMyTurn && p.id === user.id && safeGameState.diceRolled &&
                                        ((relPos === -1 && safeGameState.lastDice === 6) || (relPos >= 0 && relPos + safeGameState.lastDice <= 56));

                                    return (
                                        <motion.div
                                            layout
                                            initial={{ scale: 0, opacity: 0 }}
                                            animate={{ scale: 1, opacity: 1 }}
                                            exit={{ scale: 0, opacity: 0 }}
                                            key={`${p.id}-t${tIdx}`}
                                            className="absolute flex items-center justify-center pointer-events-none z-30"
                                            style={{
                                                left: `${(coords.x / 15) * 100}%`,
                                                top: `${(coords.y / 15) * 100}%`,
                                                width: `${100 / 15}%`,
                                                height: `${100 / 15}%`,
                                            }}
                                        >
                                            <motion.div
                                                className={`w-[85%] h-[85%] rounded-full shadow-[0_8px_10px_rgba(0,0,0,0.6),inset_0_-5px_15px_rgba(0,0,0,0.5)] flex flex-col items-center pt-[15%] transition-transform
                                                   ${canMove ? 'pointer-events-auto cursor-pointer border-white ring-4 ring-white/50 animate-bounce z-50 shadow-[0_0_20px_#ffffff]' : 'border-black/50 pointer-events-none'}
                                                `}
                                                style={{
                                                    background: `radial-gradient(circle at 35% 35%, ${COLOR_MAP[pColorName]} 5%, #000 120%)`,
                                                    borderWidth: '2px'
                                                }}
                                                whileTap={canMove ? { scale: 0.8 } : {}}
                                                onClick={() => handleTokenClick(tIdx, p.id)}
                                            >
                                                {/* Mini cute eyes for characters! */}
                                                <div className="flex gap-[15%] w-[45%] h-[30%]">
                                                    <div className="w-[45%] h-full bg-white rounded-full relative shadow-[0_2px_4px_rgba(0,0,0,0.5)]">
                                                        <div className="absolute w-[40%] h-[40%] bg-black rounded-full top-[30%] left-[30%]"></div>
                                                    </div>
                                                    <div className="w-[45%] h-full bg-white rounded-full relative shadow-[0_2px_4px_rgba(0,0,0,0.5)]">
                                                        <div className="absolute w-[40%] h-[40%] bg-black rounded-full top-[30%] left-[30%]"></div>
                                                    </div>
                                                </div>
                                            </motion.div>
                                        </motion.div>
                                    );
                                });
                            })}
                        </AnimatePresence>

                        {/* GIANT ABSOLUTE OVERLAY DICE BUTTON */}
                        <div className="absolute bottom-[2%] right-[2%] z-[100] flex flex-col items-center pointer-events-auto perspective-[1500px]">
                            <motion.button
                                onClick={handleRoll}
                                disabled={!isMyTurn || safeGameState.diceRolled || isRolling || safeGameState.winner}
                                animate={isRolling ? {
                                    rotateX: [0, 400, -200, 720, 1080],
                                    rotateY: [0, 360, 900, -180, 720],
                                    rotateZ: [0, 180, -90, 360, 0],
                                    scale: [1, 1.4, 0.6, 1.1, 1],
                                    z: [0, 150, -80, 50, 0],
                                    y: [0, -40, 20, -10, 0]
                                } : { rotateX: 0, rotateY: 0, rotateZ: 0, scale: 1, z: 0, y: 0 }}
                                transition={{ duration: 0.8, times: [0, 0.25, 0.5, 0.75, 1], ease: "anticipate" }}
                                className={`w-16 h-16 md:w-28 md:h-28 rounded-[20%] flex flex-col items-center justify-center border-[3px] md:border-4 shadow-[0_10px_20px_rgba(0,0,0,0.8),inset_0_5px_15px_rgba(255,255,255,0.4)] transition-colors transform-style-3d overflow-hidden ${!isMyTurn || safeGameState.winner ? 'bg-gradient-to-b from-slate-300 to-slate-500 border-slate-600 opacity-90 cursor-not-allowed'
                                    : safeGameState.diceRolled ? 'bg-gradient-to-b from-yellow-300 to-yellow-600 border-yellow-700 text-yellow-950 cursor-default shadow-[0_0_30px_rgba(234,179,8,0.8)]'
                                        : 'bg-gradient-to-b from-[#ffedb5] to-[#f5b82e] border-[#b07b1e] text-[#5e410b] hover:scale-105 shadow-[0_0_50px_rgba(234,179,8,1)] ring-4 ring-yellow-400'
                                    }`}
                                style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")' }}
                            >
                                <div className="w-full h-full flex items-center justify-center relative drop-shadow-[0_4px_10px_rgba(0,0,0,0.5)]">
                                    {/* Dynamic Dice Dots based on value 1 to 6 */}
                                    {currentFace === 1 && (
                                        <div className="w-4 h-4 md:w-6 md:h-6 bg-[#4a2e15] rounded-full shadow-inner"></div>
                                    )}
                                    {currentFace === 2 && (
                                        <div className="w-full h-full flex justify-between p-3 md:p-6 pb-4 md:pb-8">
                                            <div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full self-start shadow-inner"></div>
                                            <div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full self-end shadow-inner"></div>
                                        </div>
                                    )}
                                    {currentFace === 3 && (
                                        <div className="w-full h-full flex flex-col justify-between items-center p-3 md:p-6 pb-4 md:pb-8">
                                            <div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full self-start shadow-inner"></div>
                                            <div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full self-center shadow-inner"></div>
                                            <div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full self-end shadow-inner"></div>
                                        </div>
                                    )}
                                    {currentFace === 4 && (
                                        <div className="w-full h-full flex flex-col justify-between p-3 md:p-6 pb-4 md:pb-8">
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                        </div>
                                    )}
                                    {currentFace === 5 && (
                                        <div className="w-full h-full flex flex-col justify-between p-3 md:p-6 pb-4 md:pb-8">
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                            <div className="flex justify-center w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                        </div>
                                    )}
                                    {currentFace === 6 && (
                                        <div className="w-full h-full flex flex-col justify-between p-3 md:p-6 pb-4 md:pb-8">
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                            <div className="flex justify-between w-full"><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div><div className="w-3 h-3 md:w-5 md:h-5 bg-[#4a2e15] rounded-full shadow-inner"></div></div>
                                        </div>
                                    )}
                                </div>
                            </motion.button>
                            {safeGameState.diceRolled && isMyTurn && (
                                <div className="absolute -top-3 -right-3 md:-top-5 md:-right-5 bg-green-500 text-white text-[8px] md:text-sm font-black uppercase px-2 md:px-4 py-1 rounded-full shadow-lg animate-bounce border-2 border-white whitespace-nowrap">
                                    Move!
                                </div>
                            )}
                        </div>
                    </div>
                </div>

            </motion.div>

            {/* ACTION STATUS / HISTORY */}
            {safeGameState.winner && (
                <div className="w-full max-w-xl mx-auto mt-4 px-4 z-20">
                    <button onClick={() => socket.emit('restartGame', { roomCode, userId: user.id })} className="w-full py-4 bg-yellow-500 hover:bg-yellow-400 text-yellow-950 rounded-xl font-black uppercase tracking-widest border-[4px] border-[#825424] shadow-[0_10px_20px_rgba(0,0,0,0.8)] text-xl" style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")' }}>
                        Play Rematch!
                    </button>
                </div>
            )}

            <div className="w-full max-w-4xl mx-auto flex flex-col md:flex-row gap-4 mt-8">
                {/* Recent History Feed */}
                <div className="flex-1 bg-[#4a2e15]/80 rounded-3xl p-4 md:p-6 border-[4px] border-[#3d2210] shadow-xl flex flex-col relative z-20" style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/wood-pattern.png")' }}>
                    <h3 className="text-amber-200 font-bold uppercase tracking-widest text-xs mb-4">Live History Log</h3>
                    <div className="w-full flex flex-col gap-2 overflow-y-auto max-h-48 custom-scrollbar">
                        {safeGameState.history?.slice().reverse().map((h, i) => {
                            const p = safeGameState.players?.find(p => p.id === h.userId);
                            return (
                                <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} key={i} className={`flex justify-between items-center text-xs p-3 rounded-xl border-2 ${h.type === 'capture' ? 'bg-red-950/90 border-red-900 shadow-inner' : 'bg-black/30 border-[#3d2210]'}`}>
                                    <span className="text-white font-bold truncate">{p?.name}</span>
                                    {h.type === 'roll' ? (
                                        <div className="flex gap-2 items-center">
                                            <span className="text-amber-500">Rolled a </span>
                                            <span className="font-black text-white text-lg bg-black/50 px-3 py-1 rounded shadow-inner text-[#FDE047]">{h.value}</span>
                                        </div>
                                    ) : h.type === 'capture' ? (
                                        <span className="text-red-500 font-black uppercase tracking-widest animate-pulse">Eliminated Opponent ≡ƒÆÇ</span>
                                    ) : null}
                                </motion.div>
                            )
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

